final:
module RefModule(
    input clk,
    input rst_n,
    output reg [2:0] gray_code
);

reg [2:0] obf_binary_counter;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        obf_binary_counter <= 3'b000;
    end else begin
        obf_binary_counter <= obf_binary_counter + 1;
    end
end

always @(*) begin
    gray_code = obf_binary_counter ^ (obf_binary_counter >> 1);
end

endmodule
